import { Box, Flex, Grid, Icon, Text } from "@chakra-ui/react";
import React from "react";
import { Bar, Pie } from "react-chartjs-2";
import Chart from "chart.js/auto";
import AdminNavTop from "../AdminNavTop";
import { BiMale } from "react-icons/bi";
import { FaVideo } from "react-icons/fa";
import { FiBook } from "react-icons/fi";
import { FiFilm } from "react-icons/fi";

const DashBoard = () => {
  const data = {
    labels: ["January", "February", "March", "April", "May", "June"],
    datasets: [
      {
        label: "Courses",
        data: [12, 19, 3, 5, 2, 3],
        backgroundColor: "rgba(235, 50, 90, 0.6)",
        borderColor: "rgba(75,192,192,1)",
        borderWidth: 1,
      },
    ],
  };
  const datapie = {
    labels: ["Full Stack", "Frontend", "Backend"],
    datasets: [
      {
        data: [300, 50, 100],
        backgroundColor: ["#FF6384", "#36A2EB", "#FFCE56"],
        hoverBackgroundColor: ["#FF6384", "#36A2EB", "#FFCE56"],
      },
    ],
  };
  const datapie1 = {
    labels: ["live", "recorded", "offline"],
    datasets: [
      {
        data: [300, 50, 100],
        backgroundColor: ["#FF6384", "#36A2EB", "#FFCE56"],
        hoverBackgroundColor: ["#FF6384", "#36A2EB", "#FFCE56"],
      },
    ],
  };

  return (
  <Box bg="#f7f9fa" minH="100vh" p={6}>
    <AdminNavTop />

    <Box mt="80px">
      {/* KPI CARDS */}
      <Grid
        templateColumns={{
          base: "1fr",
          md: "repeat(2,1fr)",
          lg: "repeat(4,1fr)",
        }}
        gap={6}
        mb={8}
      >
        {[
          { title: "Subscribers", value: "2,344", icon: BiMale },
          { title: "Videos", value: "5,123", icon: FaVideo },
          { title: "Courses", value: "1,200", icon: FiBook },
          { title: "Watch Time", value: "999+ hrs", icon: FiFilm },
        ].map((item, i) => (
          <Box
            key={i}
            bg="white"
            p={5}
            borderRadius="lg"
            boxShadow="lg"
          >
            <Flex justify="space-between" align="center">
              <Text color="gray.500">{item.title}</Text>
              <Icon as={item.icon} boxSize={6} color="#A435F0" />
            </Flex>

            <Text fontSize="2xl" fontWeight="bold" mt={3}>
              {item.value}
            </Text>

            <Text fontSize="sm" color="green.500" mt={2}>
              +12% this month
            </Text>
          </Box>
        ))}
      </Grid>

      {/* BAR CHART */}
      <Box
        bg="white"
        p={6}
        borderRadius="lg"
        boxShadow="lg"
        mb={8}
      >
        <Text fontSize="lg" fontWeight="bold" mb={4}>
          Monthly Growth
        </Text>

        <Box h="300px">
          <Bar
            data={{
              ...data,
              datasets: [
                {
                  ...data.datasets[0],
                  backgroundColor: "#A435F0",
                  borderRadius: 6,
                },
              ],
            }}
            options={{ maintainAspectRatio: false }}
          />
        </Box>
      </Box>

      {/* PIE CHARTS */}
      <Grid
        templateColumns={{
          base: "1fr",
          md: "repeat(2,1fr)",
        }}
        gap={6}
      >
        <Box bg="white" p={6} borderRadius="lg" boxShadow="lg">
          <Text fontWeight="bold" mb={4}>
            Course Categories
          </Text>

          <Box h="250px">
            <Pie
              data={{
                ...datapie,
                datasets: [
                  {
                    ...datapie.datasets[0],
                    backgroundColor: [
                      "#A435F0",
                      "#c084fc",
                      "#e9d5ff",
                    ],
                  },
                ],
              }}
              options={{ maintainAspectRatio: false }}
            />
          </Box>
        </Box>

        <Box bg="white" p={6} borderRadius="lg" boxShadow="lg">
          <Text fontWeight="bold" mb={4}>
            Video Types
          </Text>

          <Box h="250px">
            <Pie
              data={{
                ...datapie1,
                datasets: [
                  {
                    ...datapie1.datasets[0],
                    backgroundColor: [
                      "#A435F0",
                      "#c084fc",
                      "#e9d5ff",
                    ],
                  },
                ],
              }}
              options={{ maintainAspectRatio: false }}
            />
          </Box>
        </Box>
      </Grid>
    </Box>
  </Box>
);
};

export default DashBoard;
